mapper.sql:
WHERE deleted = 0

    AND student_no LIKE CONCAT('%', #{query.studentNo}, '%')


    AND chinese_name LIKE CONCAT('%', #{query.chineseName}, '%')


    AND english_name LIKE CONCAT('%', #{query.englishName}, '%')


    AND nationality = #{query.nationality}


    AND college LIKE CONCAT('%', #{query.college}, '%')


    AND major LIKE CONCAT('%', #{query.major}, '%')


    AND student_status = #{query.studentStatus}


    AND status = #{query.status}
